// Find the target domain in the organic results, capture the #1
// competitor and any noteworthy SERP features.

const input = $('Loop Keywords').item.json;
const keyword = String(input.keyword || '').trim();

// Regex extractor — works for bare domains, full URLs, and protocol-less
// strings. Avoids `new URL()` because n8n's Code node sandbox can drop it.
const hostOf = (u) => {
  if (!u) return '';
  const s = String(u).trim().toLowerCase();
  const m = s.match(/^(?:[a-z][a-z0-9+.-]*:\/\/)?(?:[^@/]+@)?([^/?#:]+)/i);
  return m ? m[1].replace(/^www\./, '') : '';
};

const targetDomain = hostOf(input.target_domain);

const response = ($input.first().json || {}).response || {};
const body = response.body || '';

let parsed = {};
try {
  parsed = typeof body === 'string' ? JSON.parse(body) : body;
} catch (e) {
  parsed = {};
}

const organic = Array.isArray(parsed.organic_results) ? parsed.organic_results : [];

let rank = 0;
let urlFound = '';
for (let i = 0; i < organic.length; i++) {
  const r = organic[i];
  const host = hostOf(r.link || r.url || '');
  if (host && (host === targetDomain || host.endsWith('.' + targetDomain))) {
    rank = Number(r.position) || (i + 1);
    urlFound = r.link || r.url || '';
    break;
  }
}

const top = organic[0] || {};
const topUrl = top.link || top.url || '';
const topDomain = hostOf(topUrl);

const features = [];
if (parsed.ai_overview || parsed.aiOverview) features.push('ai_overview');
if (parsed.featured_snippet || parsed.answer_box) features.push('featured_snippet');
if (parsed.knowledge_graph) features.push('knowledge_graph');
if (Array.isArray(parsed.related_questions) && parsed.related_questions.length) features.push('people_also_ask');
if (Array.isArray(parsed.videos) && parsed.videos.length) features.push('videos');
if (Array.isArray(parsed.images) && parsed.images.length) features.push('images');
if (Array.isArray(parsed.shopping_results) && parsed.shopping_results.length) features.push('shopping');

return [{
  json: {
    timestamp: new Date().toISOString(),
    keyword,
    target_domain: targetDomain,
    rank,
    url_found: urlFound,
    top_competitor_url: topUrl,
    top_competitor_domain: topDomain,
    serp_features: features.join(','),
  },
  pairedItem: { item: 0 },
}];

// Group the full history by (keyword, target_domain) and compare the
// two most recent snapshots per group. Flag anything that moved by
// THRESHOLD positions, entered or fell out of the top 100.

const THRESHOLD = 3;
const rows = $input.all().map(i => i.json).filter(r => r && r.keyword);

rows.sort((a, b) => String(a.timestamp).localeCompare(String(b.timestamp)));

const groups = new Map();
for (const r of rows) {
  const key = `${String(r.keyword).toLowerCase()}::${String(r.target_domain).toLowerCase()}`;
  if (!groups.has(key)) groups.set(key, []);
  groups.get(key).push(r);
}

const movements = [];
for (const [, snapshots] of groups) {
  if (snapshots.length === 0) continue;
  const latest = snapshots[snapshots.length - 1];
  const previous = snapshots.length > 1 ? snapshots[snapshots.length - 2] : null;

  const latestRank = Number(latest.rank) || 0;
  const previousRank = previous ? (Number(previous.rank) || 0) : 0;

  let change = 0;
  let direction = 'unchanged';
  if (previous) {
    if (latestRank === 0 && previousRank > 0) { direction = 'dropped_out'; change = -previousRank; }
    else if (previousRank === 0 && latestRank > 0) { direction = 'entered'; change = latestRank; }
    else if (latestRank < previousRank && latestRank > 0) { direction = 'improved'; change = previousRank - latestRank; }
    else if (latestRank > previousRank && previousRank > 0) { direction = 'declined'; change = previousRank - latestRank; }
  } else if (latestRank > 0) {
    direction = 'first_seen';
    change = latestRank;
  }

  const notable = direction === 'dropped_out' || direction === 'entered' || (direction !== 'unchanged' && Math.abs(change) >= THRESHOLD);

  movements.push({
    keyword: latest.keyword,
    target_domain: latest.target_domain,
    rank: latestRank,
    previous_rank: previousRank,
    change,
    direction,
    url_found: latest.url_found || '',
    top_competitor_url: latest.top_competitor_url || '',
    top_competitor_domain: latest.top_competitor_domain || '',
    serp_features: latest.serp_features || '',
    notable,
  });
}

const notableCount = movements.filter(m => m.notable).length;

return [{
  json: {
    threshold: THRESHOLD,
    total_keywords: movements.length,
    notable_count: notableCount,
    movements,
  },
}];

const input = $input.first().json || {};
const movements = (input.movements || []).filter(m => m.notable);

const directionLabel = {
  improved: 'up',
  declined: 'down',
  entered: 'new',
  dropped_out: 'lost',
  first_seen: 'new',
};

const directionColor = {
  improved: '#0a7d27',
  declined: '#b00020',
  entered: '#0a7d27',
  dropped_out: '#b00020',
  first_seen: '#0a7d27',
};

const esc = (s) => String(s == null ? '' : s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const fmtRank = (n) => !n ? '—' : `#${n}`;
const fmtChange = (c, dir) => {
  if (dir === 'entered' || dir === 'first_seen') return `entered at #${c}`;
  if (dir === 'dropped_out') return `lost from #${Math.abs(c)}`;
  if (c > 0) return `+${c}`;
  if (c < 0) return String(c);
  return '—';
};

movements.sort((a, b) => Math.abs(b.change) - Math.abs(a.change));

const today = new Date().toISOString().slice(0, 10);
const subject = `SERP movement digest — ${movements.length} keyword${movements.length === 1 ? '' : 's'} moved on ${today}`;

const rowsHtml = movements.map(m => `<tr>
  <td>${esc(m.keyword)}</td>
  <td>${esc(m.target_domain)}</td>
  <td style="text-align:right;">${fmtRank(m.previous_rank)}</td>
  <td style="text-align:right;font-weight:600;">${fmtRank(m.rank)}</td>
  <td style="text-align:right;color:${directionColor[m.direction] || '#444'};font-weight:600;">${esc(fmtChange(m.change, m.direction))}</td>
  <td>${esc(m.top_competitor_domain)}</td>
</tr>`).join('');

const html = `<div style="font-family:-apple-system,Segoe UI,sans-serif;max-width:760px;">
  <h2 style="margin:0 0 12px;">${esc(subject)}</h2>
  <p style="color:#555;margin:0 0 16px;">Tracked via ScraperAPI's Google Search structured endpoint. Movements of ${input.threshold}+ positions, entries and drops.</p>
  <table cellpadding="8" cellspacing="0" style="border-collapse:collapse;width:100%;font-size:14px;">
    <thead><tr style="background:#f4f4f6;text-align:left;">
      <th>Keyword</th><th>Domain</th><th style="text-align:right;">Was</th><th style="text-align:right;">Now</th><th style="text-align:right;">Change</th><th>Top result</th>
    </tr></thead>
    <tbody>${rowsHtml}</tbody>
  </table>
</div>`;

const text = movements.map(m => `• ${m.keyword} (${m.target_domain}): ${fmtRank(m.previous_rank)} → ${fmtRank(m.rank)} [${directionLabel[m.direction] || m.direction}]`).join('\n');

return [{ json: { count: movements.length, subject, html, text } }];
